import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader
import torchvision.models as models
import torchvision.transforms as transforms
from torchvision.datasets import ImageFolder
import urllib.request
import os
import ssl
from pathlib import Path
import hashlib
from tqdm import tqdm


class ModelDownloader:
    def __init__(self, cache_dir='./model_cache'):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        
    def download_from_url(self, url, filename=None):
        if filename is None:
            filename = hashlib.md5(url.encode()).hexdigest() + '.pth'
        
        filepath = self.cache_dir / filename
        
        if filepath.exists():
            print(f"Model already cached at {filepath}")
            return str(filepath)
        
        print(f"Downloading model from {url}")
        
        ssl._create_default_https_context = ssl._create_unverified_context
        
        class DownloadProgressBar(tqdm):
            def update_to(self, b=1, bsize=1, tsize=None):
                if tsize is not None:
                    self.total = tsize
                self.update(b * bsize - self.n)
        
        with DownloadProgressBar(unit='B', unit_scale=True, miniters=1, desc=filename) as t:
            urllib.request.urlretrieve(url, filepath, reporthook=t.update_to)
        
        print(f"Model downloaded to {filepath}")
        return str(filepath)
    
    def load_checkpoint(self, path_or_url, map_location='cpu'):
        if path_or_url.startswith('http://') or path_or_url.startswith('https://'):
            path = self.download_from_url(path_or_url)
        else:
            path = path_or_url
        
        print(f"Loading checkpoint from {path}")
        checkpoint = torch.load(path, map_location=map_location)
        return checkpoint


class TransferLearningPipeline:
    def __init__(self, model_name='resnet50', num_classes=10, device='cuda'):
        self.device = torch.device(device if torch.cuda.is_available() else 'cpu')
        self.model_name = model_name
        self.num_classes = num_classes
        self.model = None
        self.downloader = ModelDownloader()
        
    def load_pretrained_model(self, custom_checkpoint_url=None):
        if custom_checkpoint_url:
            checkpoint = self.downloader.load_checkpoint(custom_checkpoint_url, map_location=self.device)
            
            if self.model_name == 'resnet50':
                self.model = models.resnet50(pretrained=False)
            elif self.model_name == 'resnet18':
                self.model = models.resnet18(pretrained=False)
            elif self.model_name == 'vgg16':
                self.model = models.vgg16(pretrained=False)
            elif self.model_name == 'mobilenet_v2':
                self.model = models.mobilenet_v2(pretrained=False)
            else:
                raise ValueError(f"Unsupported model: {self.model_name}")
            
            if 'state_dict' in checkpoint:
                self.model.load_state_dict(checkpoint['state_dict'], strict=False)
            elif 'model' in checkpoint:
                self.model.load_state_dict(checkpoint['model'], strict=False)
            else:
                self.model.load_state_dict(checkpoint, strict=False)
            
            print(f"Loaded custom checkpoint for {self.model_name}")
        else:
            if self.model_name == 'resnet50':
                self.model = models.resnet50(pretrained=True)
            elif self.model_name == 'resnet18':
                self.model = models.resnet18(pretrained=True)
            elif self.model_name == 'vgg16':
                self.model = models.vgg16(pretrained=True)
            elif self.model_name == 'mobilenet_v2':
                self.model = models.mobilenet_v2(pretrained=True)
            else:
                raise ValueError(f"Unsupported model: {self.model_name}")
            
            print(f"Loaded pretrained {self.model_name} from torchvision")
        
        self.modify_classifier()
        self.model.to(self.device)
        
    def modify_classifier(self):
        if 'resnet' in self.model_name:
            num_ftrs = self.model.fc.in_features
            self.model.fc = nn.Linear(num_ftrs, self.num_classes)
        elif 'vgg' in self.model_name:
            num_ftrs = self.model.classifier[6].in_features
            self.model.classifier[6] = nn.Linear(num_ftrs, self.num_classes)
        elif 'mobilenet' in self.model_name:
            num_ftrs = self.model.classifier[1].in_features
            self.model.classifier[1] = nn.Linear(num_ftrs, self.num_classes)
    
    def freeze_base_layers(self, freeze=True):
        if 'resnet' in self.model_name or 'mobilenet' in self.model_name:
            for param in self.model.parameters():
                param.requires_grad = not freeze
            
            if 'resnet' in self.model_name:
                for param in self.model.fc.parameters():
                    param.requires_grad = True
            elif 'mobilenet' in self.model_name:
                for param in self.model.classifier.parameters():
                    param.requires_grad = True
        elif 'vgg' in self.model_name:
            for param in self.model.features.parameters():
                param.requires_grad = not freeze
            for param in self.model.classifier.parameters():
                param.requires_grad = True
        
        print(f"Base layers frozen: {freeze}")
    
    def prepare_data_loaders(self, train_dir, val_dir=None, batch_size=32, num_workers=4):
        transform_train = transforms.Compose([
            transforms.RandomResizedCrop(224),
            transforms.RandomHorizontalFlip(),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        transform_val = transforms.Compose([
            transforms.Resize(256),
            transforms.CenterCrop(224),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        train_dataset = ImageFolder(train_dir, transform=transform_train)
        train_loader = DataLoader(train_dataset, batch_size=batch_size, shuffle=True, num_workers=num_workers)
        
        val_loader = None
        if val_dir:
            val_dataset = ImageFolder(val_dir, transform=transform_val)
            val_loader = DataLoader(val_dataset, batch_size=batch_size, shuffle=False, num_workers=num_workers)
        
        return train_loader, val_loader
    
    def fine_tune(self, train_loader, val_loader=None, epochs=10, lr=0.001, freeze_base=True):
        if freeze_base:
            self.freeze_base_layers(True)
        
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), lr=lr)
        scheduler = optim.lr_scheduler.StepLR(optimizer, step_size=7, gamma=0.1)
        
        best_acc = 0.0
        
        for epoch in range(epochs):
            print(f"\nEpoch {epoch+1}/{epochs}")
            print("-" * 50)
            
            self.model.train()
            running_loss = 0.0
            running_corrects = 0
            total = 0
            
            pbar = tqdm(train_loader, desc="Training")
            for inputs, labels in pbar:
                inputs = inputs.to(self.device)
                labels = labels.to(self.device)
                
                optimizer.zero_grad()
                
                outputs = self.model(inputs)
                loss = criterion(outputs, labels)
                _, preds = torch.max(outputs, 1)
                
                loss.backward()
                optimizer.step()
                
                running_loss += loss.item() * inputs.size(0)
                running_corrects += torch.sum(preds == labels.data)
                total += labels.size(0)
                
                pbar.set_postfix({'loss': running_loss/total, 'acc': running_corrects.double().item()/total})
            
            epoch_loss = running_loss / total
            epoch_acc = running_corrects.double() / total
            
            print(f"Train Loss: {epoch_loss:.4f} Acc: {epoch_acc:.4f}")
            
            if val_loader:
                val_loss, val_acc = self.validate(val_loader, criterion)
                print(f"Val Loss: {val_loss:.4f} Acc: {val_acc:.4f}")
                
                if val_acc > best_acc:
                    best_acc = val_acc
                    self.save_checkpoint(f'best_model_{self.model_name}.pth', epoch, optimizer, best_acc)
            
            scheduler.step()
        
        print(f"\nBest validation accuracy: {best_acc:.4f}")
        return self.model
    
    def validate(self, val_loader, criterion):
        self.model.eval()
        running_loss = 0.0
        running_corrects = 0
        total = 0
        
        with torch.no_grad():
            for inputs, labels in tqdm(val_loader, desc="Validation"):
                inputs = inputs.to(self.device)
                labels = labels.to(self.device)
                
                outputs = self.model(inputs)
                loss = criterion(outputs, labels)
                _, preds = torch.max(outputs, 1)
                
                running_loss += loss.item() * inputs.size(0)
                running_corrects += torch.sum(preds == labels.data)
                total += labels.size(0)
        
        val_loss = running_loss / total
        val_acc = running_corrects.double() / total
        
        return val_loss, val_acc
    
    def save_checkpoint(self, filename, epoch, optimizer, accuracy):
        checkpoint = {
            'epoch': epoch,
            'model_name': self.model_name,
            'state_dict': self.model.state_dict(),
            'optimizer': optimizer.state_dict(),
            'accuracy': accuracy,
            'num_classes': self.num_classes
        }
        torch.save(checkpoint, filename)
        print(f"Checkpoint saved to {filename}")
    
    def load_finetuned_model(self, checkpoint_path):
        checkpoint = torch.load(checkpoint_path, map_location=self.device)
        self.model.load_state_dict(checkpoint['state_dict'])
        print(f"Loaded fine-tuned model from {checkpoint_path}")
        return checkpoint


class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


def main():
    pipeline = TransferLearningPipeline(
        model_name='resnet50',
        num_classes=10,
        device='cuda'
    )
    
    pipeline.load_pretrained_model()
    
    train_loader, val_loader = pipeline.prepare_data_loaders(
        train_dir='./data/train',
        val_dir='./data/val',
        batch_size=32
    )
    
    model = pipeline.fine_tune(
        train_loader=train_loader,
        val_loader=val_loader,
        epochs=10,
        lr=0.001,
        freeze_base=True
    )
    
    print("\nFine-tuning completed!")


if __name__ == '__main__':
    main()